'use client';

import Link from 'next/link';
import { useMemo } from 'react';
import { useParams } from 'next/navigation';
import { Clock3, FileText, MessageSquareText, UserRound, Video } from 'lucide-react';
import { PageHeader, SurfaceCard } from '../../../components/ui';
import { activeMockUser, canView, mockLessons, mockScheduledLessons } from '../../../mocks';
import styles from './page.module.scss';

export default function LessonPage() {
  const params = useParams<{ lessonId: string }>();
  const lessonId = params?.lessonId;
  const hasAccess = canView('dashboard', activeMockUser.role);

  const lesson = useMemo(() => {
    if (!lessonId) return null;
    const candidate = mockScheduledLessons.find((item) => item.id === lessonId);
    if (!candidate) return null;
    if (activeMockUser.role === 'student' && candidate.studentId !== activeMockUser.id) return null;
    if (activeMockUser.role === 'teacher' && candidate.teacherId !== activeMockUser.id) return null;
    return candidate;
  }, [lessonId]);

  const lessonMeta = mockLessons.find((item) => item.id === lesson?.lessonId);
  const materials = lesson?.materials ?? [];
  const statusLabel =
    lesson?.status === 'planned'
      ? 'Planned'
      : lesson?.status === 'completed'
        ? 'Completed'
        : 'Cancelled';

  if (!hasAccess || !lesson) return null;

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title="Lesson"
        subtitle="Detailed lesson view"
      />

      <div className={styles.layout}>
        <SurfaceCard className={styles.sidebarCard}>
          <Link href="/lessons" className={styles.backLink}>
            ← Back to lessons
          </Link>
          <h1 className={styles.lessonTitle}>{lesson.title}</h1>
          <span className={styles.lessonType}>{lesson.type}</span>
          <span
            className={`${styles.status} ${lesson.status === 'planned' ? styles.statusPlanned : ''} ${lesson.status === 'completed' ? styles.statusCompleted : ''} ${lesson.status === 'cancelled' ? styles.statusCancelled : ''}`}
          >
            {statusLabel}
          </span>

          <div className={styles.metaList}>
            <div className={styles.metaItem}>
              <Clock3 size={14} />
              <span>
                {lesson.date} · {lesson.startTime} - {lesson.endTime}
              </span>
            </div>
            <div className={styles.metaItem}>
              <UserRound size={14} />
              <span>{lesson.teacherName}</span>
            </div>
            <div className={styles.metaItem}>
              <UserRound size={14} />
              <span>{lesson.studentName}</span>
            </div>
          </div>

          <a href="#" className={styles.meetButton} onClick={(event) => event.preventDefault()}>
            <Video size={16} />
            Join lesson call
          </a>
          <Link href="/calendar" className={styles.calendarButton}>
            Open in Calendar
          </Link>

          <p className={styles.description}>
            {lessonMeta?.description || lesson.notes || 'Lesson details are available in content cards.'}
          </p>
        </SurfaceCard>

        <div className={styles.content}>
          <SurfaceCard className={styles.sectionCard}>
            <div className={styles.sectionHead}>Lesson plan</div>
            <p className={styles.sectionText}>{lesson.lessonPlan || lesson.notes || 'No lesson plan yet.'}</p>
          </SurfaceCard>

          <SurfaceCard className={styles.sectionCard}>
            <div className={styles.sectionHead}>Materials</div>
            {materials.length > 0 ? (
              <div className={styles.materialList}>
                {materials.map((material) => (
                  <div key={material.id} className={styles.materialItem}>
                    <FileText size={15} />
                    <div>
                      <div className={styles.materialTitle}>{material.text || 'Lesson material'}</div>
                      <div className={styles.materialMeta}>{material.kind}</div>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <p className={styles.sectionText}>No materials added.</p>
            )}
          </SurfaceCard>

          <SurfaceCard className={styles.sectionCard}>
            <div className={styles.sectionHead}>Homework</div>
            <p className={styles.sectionText}>{lesson.homework?.text || 'No homework assigned.'}</p>
          </SurfaceCard>

          <SurfaceCard className={styles.sectionCard}>
            <div className={styles.sectionHeadWithIcon}>
              <MessageSquareText size={15} />
              <span>Student response</span>
            </div>
            <p className={styles.sectionText}>{lesson.studentResponse?.text || 'No student response yet.'}</p>
          </SurfaceCard>
        </div>
      </div>
    </div>
  );
}
